CREATE TABLE [dbo].[ProcessLog](	  [ProcessLog_Id] INT NOT NULL IDENTITY(1,1)	, [FileID] INT NULL	, [Campaign_Name] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [QuoteID] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [QuoteLine_ID] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Job_Name] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [QuoteLine_Name] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NOT NULL	, [Job_Specific_Name] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [SBQQ__ProductName__c] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Parent_ID] AS (CONVERT([int],right([QuoteLine_Name],(7))))	, [Package_Code] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Phase_Code] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Mail_Date] DATE NULL	, [Data_Selection_Criteria] VARCHAR(MAX) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Estimated_Qty] INT NULL	, [Prelim_Inv_Qty] INT NULL	, [Delivered_Qty] INT NULL	, [AudienceName] VARCHAR(100) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [AudienceCode] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [CreativeName] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [CreativeCode] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [CreativeAbbreviated] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [AsktableCode] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Multiplier] DECIMAL(18,2) NULL	, [TestControl_CD_Out] VARCHAR(50) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Dups_Drop] INT NULL	, [NCOA_Drop] INT NULL	, [ORIGINAL] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [NCOA] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [QC_File] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [QC_Report] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [NCOA_Link_Report] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [QC_Approved] BIT NOT NULL DEFAULT((0))	, [Approved_Date] DATE NULL	, [ApprovedBy] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Rejected_Date] DATE NULL	, [RejectedBy] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Data_Loader] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Lettershop_FileName] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [PromoHarvester_FileName] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Notify_QCFile_Created] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Notify_Lettershop_Created] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Notify_NCOA_Created] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Notify_MergeDup_Created] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Notify_AppealTracking_Created] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Notify_PromoHarvest_Created] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Notify_QCOutput_Created] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [Seed_Processed] BIT NOT NULL DEFAULT((0))	, [Scanline_Processed] BIT NOT NULL DEFAULT((0))	, [Scanline_Error] VARCHAR(255) COLLATE SQL_Latin1_General_CP1_CI_AS NULL	, [AskArray_Processed] BIT NOT NULL DEFAULT((0))	, [Is_Acquisition] AS (case when charindex('Acquisition',[AudienceName])>(0) OR charindex('Prospect',[AudienceName])>(0) then (1) else (0) end)	, [CreatedDate] DATETIME NOT NULL DEFAULT(getdate())	, [LastModifiedDate] DATETIME NOT NULL DEFAULT(getdate())	, CONSTRAINT [PK_QC_ProcessLog] PRIMARY KEY ([ProcessLog_Id] ASC))CREATE UNIQUE NONCLUSTERED INDEX [NonClusteredIndex-20250310-112600] ON [dbo].[ProcessLog] ([QuoteLine_Name] ASC)CREATE NONCLUSTERED INDEX [NonClusteredIndex-20250330-214447] ON [dbo].[ProcessLog] ([FileID] ASC)CREATE NONCLUSTERED INDEX [NonClusteredIndex-20250330-214531] ON [dbo].[ProcessLog] ([Parent_ID] ASC)CREATE NONCLUSTERED INDEX [NonClusteredIndex-20250819-155745] ON [dbo].[ProcessLog] ([Quote